#include <bits/stdc++.h>
using namespace std;
int n;
int he(int d){
	int num=0,x=d;
	while(x){
		num+=x%10;
		x/=10;
	}
	return num;
} 
int main(){
	cin>>n;
	for(int i=0;i<n;i++){
		int h=0;
		string a;
		cin>>a;
		reverse(a.begin(),a.end());
		for(int j=0;j<int(a.size());j+=2){
			int x=a[j]-'0';
			x*=7;
			while(x/10){
				x=he(x);
			}
			a[j]=x+'0';
		}
		for(int j=0;j<a.size();j++){
			h=h*10+(a[j]-'0');
		}
		if(he(h)%8==0){
			cout<<"T\n";
		}else{
			cout<<"F\n";
		}
	}
	return 0;
}
